var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// .NET 9: Singleton must not capture a Scoped service. ValidateScopes (now
// enabled by default in Development) would throw at startup. Use a Scoped
// registration so CacheService gets its own IUserService per scope.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// .NET 9: HttpClientFactory now defaults to SocketsHttpHandler. The old
// cast to HttpClientHandler throws InvalidCastException. Use
// ConfigurePrimaryHttpMessageHandler to set the handler type explicitly.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });
// .NET 9: Trace-level HttpClientFactory logs redact all header values by
// default. Allowlist the specific non-sensitive headers you need to debug.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h => h != "X-Request-Id" && h != "X-Correlation-Id"));
// .NET 9: ForwardedHeadersMiddleware now ignores X-Forwarded-* headers from
// proxies not in KnownProxies/KnownNetworks. Add your reverse proxy address.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(System.Net.IPAddress.Parse("127.0.0.1"));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

